refsection.programlisting:
      
b=2;
n=b^4;
u=lowdisc_ldgen(n,1,"halton");
for k=1:n
    d=number_tobary(k,b);
    dstr=strcat(string(d),"");
    drev=strcat(string(d($:-1:1)),"");
    mprintf("k=%d=(%s)_%d, r=(0.%s)_%d=%f\n",..
    k,dstr,b,drev,b,u(k,1))
end

   
 b=3;
 n=b^3;
 u=lowdisc_ldgen(n,2,"halton");
 for k=1:n
     d=number_tobary(k,b);
     dstr=strcat(string(d),"");
     drev=strcat(string(d($:-1:1)),"");
     mprintf("k=%d=(%s)_%d, r=(0.%s)_%d=%f\n",..
     k,dstr,b,drev,b,u(k,2))
 end

      
s=3;
b=5;
npoints=b^2;
u=lowdisc_ldgen(npoints,s,"halton");
u=[zeros(1,s);u];
u=u(:,s);
scf();
for i=0:b-1
    indices=i*npoints/b+1:(i+1)*npoints/b;
    plot(u(indices)',i,"bo")
    xstring(u(indices)',i,string(indices))
end
a = gca();
a.data_bounds=[
0 -1
1 b
];
st=msprintf("Van Der Corput Sequence, Base %d, %d Points",b,npoints);
xtitle(st,"X","Block Index")

      
sigma=[0,2,1];
b=3;
for index=1:10
    r = scrambleVDC(index,b,sigma);
    mprintf("index=%d, r=%f\n",index,r)
end

refsection.para:
The following function computes the RR2 scrambling
for the i-th dimension of a point set with s dimensions,
using the bases in the matrix b.

refsection.programlisting:
      
s=3;
primemat=number_primes100();
b=primemat(1:s);
for i=1:s
    sigma=RR2Scrambling(s,i,b);
    sigmastr=strcat(string(sigma),",");
    mprintf("i=%d, [%s]\n",i,sigmastr);
end
